// NORMALIZATION: Convert ON/OFF → Enable/Disable
// --------------------------------------------
function normalize(v) {
    if (v === null || v === undefined) return v;
    let x = v.toString().trim().toLowerCase();

    if (x === "on") return "Enable";
    if (x === "off") return "Disable";
    if (x === "enable") return "Enable";
    if (x === "disable") return "Disable";

    return v;
}

